export function textHidden(){document.addEventListener("DOMContentLoaded",(()=>{const e=document.querySelector(".read-more"),t=document.querySelector(".read-less"),d=document.querySelector(".hidden"),n=n=>{d.classList.toggle("visible",n),e.classList.toggle("hidden",n),t.classList.toggle("visible",n)};e.addEventListener("click",(e=>{e.preventDefault(),n(!0)})),t.addEventListener("click",(e=>{e.preventDefault(),n(!1)}))}))}